  },
  {
    "biasType": "Dismissive Attitude",
    "biasedText": "This is a nothing burger.",
    "explanation": "Describing the issue as a 'nothing burger' minimizes the concerns raised by the opposition and suggests their arguments are baseless without a balanced assessment."
  },
  {
    "biasType": "Partisan Framing",
    "biasedText": "If you’re going to try to take a shot from the Grassy Knoll, be sure you have your stuff together.",
    "explanation": "This allusion portrays Democrats' actions as both conspiratorial and incompetent, reinforcing a negative stereotype."
  },
  {
    "biasType": "Loaded Language",
    "biasedText": "liberal can whine and harass ICE all they want—people who shouldn’t be here are going back—Adios, sayonara, annyeonghi gaseyo.",
    "explanation": "The use of 'whine' and the dismissive multilingual farewells disparages opponents of deportation policies and immigrants in general, rather than presenting arguments factually."
  },
  {
    "biasType": "Partisan Framing",
    "biasedText": "Do you enjoy Townhall's conservative reporting that takes on the radical left and woke media?",
    "explanation": "Phrasing like 'radical left' and 'woke media' positions the article as being in opposition to these groups, which signals to the reader that coverage will not be even-handed."
  }
]

